const COLORS = {
  reset: '\x1b[0m',
  red: '\x1b[31m',
  green: '\x1b[32m',
  yellow: '\x1b[33m',
  blue: '\x1b[34m',
  magenta: '\x1b[35m',
  cyan: '\x1b[36m',
};

const CONFIG = {
  projectRoot: process.env.PROJECT_ROOT || process.cwd(),
  nodeEnv: process.env.NODE_ENV || 'production',
  deployTarget: process.env.DEPLOY_TARGET || 'production',
  deployHost: process.env.DEPLOY_HOST || 'deploy.example.com',
  deployUser: process.env.DEPLOY_USER || 'deploy',
  deployPath: process.env.DEPLOY_PATH || '/var/www/app',
  deployPort: process.env.DEPLOY_PORT || '22',
  buildDir: process.env.BUILD_DIR || 'dist',
  testTimeout: parseInt(process.env.TEST_TIMEOUT) || 120000,
  maxRetries: parseInt(process.env.MAX_RETRIES) || 3,
  parallelTests: process.env.PARALLEL_TESTS !== 'false',
  skipTests: process.env.SKIP_TESTS === 'true',
  skipLint: process.env.SKIP_LINT === 'true',
  skipDeploy: process.env.SKIP_DEPLOY === 'true',
  cacheDir: process.env.CACHE_DIR || path.join(os.tmpdir(), 'cicd-cache'),
  artifactDir: process.env.ARTIFACT_DIR || 'artifacts',
  healthCheckUrl: process.env.HEALTH_CHECK_URL || '',
  healthCheckTimeout: parseInt(process.env.HEALTH_CHECK_TIMEOUT) || 60000,
  rollbackOnFailure: process.env.ROLLBACK_ON_FAILURE !== 'false',
  notifySlack: process.env.SLACK_WEBHOOK_URL || '',
  dockerEnabled: process.env.DOCKER_ENABLED === 'true',
  dockerImage: process.env.DOCKER_IMAGE || 'app',
  dockerRegistry: process.env.DOCKER_REGISTRY || '',
};

class PipelineTimer {
  constructor() {
    this.timers = {};
    this.pipelineStart = Date.now();
  }

  start(stage) {
    this.timers[stage] = Date.now();
  }

  end(stage) {
    if (this.timers[stage]) {
      const duration = Date.now() - this.timers[stage];
      return duration;
    }
    return 0;
  }

  totalElapsed() {
    return Date.now() - this.pipelineStart;
  }

  formatMs(ms) {
    if (ms < 1000) return `${ms}ms`;
    if (ms < 60000) return `${(ms / 1000).toFixed(2)}s`;
    return `${(ms / 60000).toFixed(2)}min`;
  }
}

class Logger {
  static log(message, color = COLORS.reset) {
    const timestamp = new Date().toISOString();
    console.log(`${color}[${timestamp}] ${message}${COLORS.reset}`);
  }

  static info(message) { this.log(`ℹ️  ${message}`, COLORS.blue); }
  static success(message) { this.log(`✅ ${message}`, COLORS.green); }
  static warn(message) { this.log(`⚠️  ${message}`, COLORS.yellow); }
  static error(message) { this.log(`❌ ${message}`, COLORS.red); }
  static stage(message) { this.log(`\n🚀 ${message}`, COLORS.magenta); }
  static step(message) { this.log(`   → ${message}`, COLORS.cyan); }

  static banner(text) {
    const line = '═'.repeat(60);
    console.log(`\n${COLORS.cyan}╔${line}╗`);
    console.log(`║ ${text.padEnd(58)} ║`);
    console.log(`╚${line}╝${COLORS.reset}\n`);
  }
}

class Pipeline {
  constructor() {
    this.timer = new PipelineTimer();
    this.results = {};
    this.commitHash = '';
    this.commitMessage = '';
    this.branch = '';
    this.version = '';
    this.previousDeployHash = '';
  }

  exec(command, options = {}) {
    const defaultOptions = {
      cwd: CONFIG.projectRoot,
      stdio: options.silent ? 'pipe' : 'inherit',
      env: { ...process.env, NODE_ENV: CONFIG.nodeEnv },
      timeout: options.timeout || 300000,
    };

    try {
      const result = execSync(command, { ...defaultOptions, ...options });
      return result ? result.toString().trim() : '';
    } catch (error) {
      if (options.ignoreError) {
        Logger.warn(`Command failed (ignored): ${command}`);
        return '';
      }
      throw error;
    }
  }

  execWithRetry(command, retries = CONFIG.maxRetries, options = {}) {
    for (let attempt = 1; attempt <= retries; attempt++) {
      try {
        return this.exec(command, options);
      } catch (error) {
        if (attempt === retries) {
          throw error;
        }
        Logger.warn(`Attempt ${attempt}/${retries} failed. Retrying in ${attempt * 2}s...`);
        this.exec(`sleep ${attempt * 2}`);
      }
    }
  }

  // ==================== STAGE: Initialize ====================
  async stageInit() {
    Logger.stage('STAGE 1: Initialize Pipeline');
    this.timer.start('init');

    // Gather git info
    try {
      this.commitHash = this.exec('git rev-parse --short HEAD', { silent: true });
      this.commitMessage = this.exec('git log -1 --pretty=%B', { silent: true });
      this.branch = this.exec('git rev-parse --abbrev-ref HEAD', { silent: true });
    } catch {
      Logger.warn('Not a git repository or git not available');
      this.commitHash = 'unknown';
      this.branch = 'unknown';
    }

    // Read package version
    try {
      const pkg = JSON.parse(fs.readFileSync(path.join(CONFIG.projectRoot, 'package.json'), 'utf8'));
      this.version = pkg.version || '0.0.0';
    } catch {
      this.version = '0.0.0';
    }

    Logger.step(`Branch: ${this.branch}`);
    Logger.step(`Commit: ${this.commitHash}`);
    Logger.step(`Version: ${this.version}`);
    Logger.step(`Deploy Target: ${CONFIG.deployTarget}`);
    Logger.step(`Node.js: ${process.version}`);
    Logger.step(`Platform: ${os.platform()} ${os.arch()}`);
    Logger.step(`CPUs: ${os.cpus().length}`);

    // Ensure required directories
    [CONFIG.cacheDir, CONFIG.artifactDir].forEach(dir => {
      if (!fs.existsSync(dir)) {
        fs.mkdirSync(dir, { recursive: true });
      }
    });

    // Validate environment
    this.validateEnvironment();

    const duration = this.timer.end('init');
    this.results.init = { status: 'success', duration };
    Logger.success(`Initialize completed in ${this.timer.formatMs(duration)}`);
  }

  validateEnvironment() {
    Logger.step('Validating environment...');

    // Check Node.js version
    const nodeVersion = process.version.replace('v', '');
    const majorVersion = parseInt(nodeVersion.split('.')[0]);
    if (majorVersion < 16) {
      throw new Error(`Node.js >= 16 required. Current: ${process.version}`);
    }

    // Check for required files
    const requiredFiles = ['package.json'];
    for (const file of requiredFiles) {
      const filePath = path.join(CONFIG.projectRoot, file);
      if (!fs.existsSync(filePath)) {
        throw new Error(`Required file not found: ${file}`);
      }
    }

    // Check for package-lock.json or yarn.lock
    const hasPackageLock = fs.existsSync(path.join(CONFIG.projectRoot, 'package-lock.json'));
    const hasYarnLock = fs.existsSync(path.join(CONFIG.projectRoot, 'yarn.lock'));
    const hasPnpmLock = fs.existsSync(path.join(CONFIG.projectRoot, 'pnpm-lock.yaml'));

    if (!hasPackageLock && !hasYarnLock && !hasPnpmLock) {
      Logger.warn('No lock file found. Consider adding one for reproducible builds.');
    }

    this.packageManager = hasPnpmLock ? 'pnpm' : hasYarnLock ? 'yarn' : 'npm';
    Logger.step(`Package manager detected: ${this.packageManager}`);
  }

  // ==================== STAGE: Install Dependencies ====================
  async stageInstall() {
    Logger.stage('STAGE 2: Install Dependencies');
    this.timer.start('install');

    const cacheKey = this.getDependencyCacheKey();
    const cacheHit = this.checkDependencyCache(cacheKey);

    if (cacheHit) {
      Logger.step('Dependency cache hit! Restoring from cache...');
      this.restoreDependencyCache(cacheKey);
    } else {
      Logger.step('Installing dependencies (clean install for CI)...');

      const installCommands = {
        npm: 'npm ci --prefer-offline --no-audit --no-fund',
        yarn: 'yarn install --frozen-lockfile --non-interactive',
        pnpm: 'pnpm install --frozen-lockfile',
      };

      this.execWithRetry(installCommands[this.packageManager]);
      this.saveDependencyCache(cacheKey);
    }

    // Verify node_modules
    if (!fs.existsSync(path.join(CONFIG.projectRoot, 'node_modules'))) {
      throw new Error('node_modules directory not found after install');
    }

    const duration = this.timer.end('install');
    this.results.install = { status: 'success', duration, cacheHit };
    Logger.success(`Dependencies installed in ${this.timer.formatMs(duration)} (cache: ${cacheHit ? 'HIT' : 'MISS'})`);
  }

  getDependencyCacheKey() {
    const lockFiles = {
      npm: 'package-lock.json',
      yarn: 'yarn.lock',
      pnpm: 'pnpm-lock.yaml',
    };

    const lockFile = lockFiles[this.packageManager];
    const lockPath = path.join(CONFIG.projectRoot, lockFile);

    if (fs.existsSync(lockPath)) {
      const crypto = require('crypto');
      const content = fs.readFileSync(lockPath);
      return crypto.createHash('md5').update(content).digest('hex');
    }
    return 'no-lock-file';
  }

  checkDependencyCache(cacheKey) {
    const cachePath = path.join(CONFIG.cacheDir, `deps-${cacheKey}`);
    return fs.existsSync(cachePath);
  }

  saveDependencyCache(cacheKey) {
    try {
      const cachePath = path.join(CONFIG.cacheDir, `deps-${cacheKey}`);
      this.exec(`cp -r node_modules "${cachePath}"`, { silent: true });
      Logger.step('Dependency cache saved');
    } catch {
      Logger.warn('Failed to save dependency cache');
    }
  }

  restoreDependencyCache(cacheKey) {
    const cachePath = path.join(CONFIG.cacheDir, `deps-${cacheKey}`);
    this.exec(`cp -r "${cachePath}" node_modules`, { silent: true });
  }

  // ==================== STAGE: Lint ====================
  async stageLint() {
    if (CONFIG.skipLint) {
      Logger.stage('STAGE 3: Lint (SKIPPED)');
      this.results.lint = { status: 'skipped', duration: 0 };
      return;
    }

    Logger.stage('STAGE 3: Lint & Code Quality');
    this.timer.start('lint');

    const pkg = JSON.parse(fs.readFileSync(path.join(CONFIG.projectRoot, 'package.json'), 'utf8'));
    const scripts = pkg.scripts || {};

    // Run ESLint
    if (scripts.lint) {
      Logger.step('Running linter...');
      this.exec(`${this.getRunCommand()} lint`);
    } else {
      Logger.step('No lint script found, checking for ESLint config...');
      const eslintConfigs = ['.eslintrc', '.eslintrc.js', '.eslintrc.json', '.eslintrc.yml', 'eslint.config.js'];
      const hasEslint = eslintConfigs.some(f => fs.existsSync(path.join(CONFIG.projectRoot, f)));

      if (hasEslint) {
        this.exec('npx eslint . --ext .js,.jsx,.ts,.tsx --max-warnings 0', { ignoreError: true });
      } else {
        Logger.warn('No linter configuration found');
      }
    }

    // Run type checking if TypeScript
    if (scripts['type-check'] || scripts.typecheck) {
      Logger.step('Running type check...');
      const typeCheckScript = scripts['type-check'] ? 'type-check' : 'typecheck';
      this.exec(`${this.getRunCommand()} ${typeCheckScript}`);
    } else if (fs.existsSync(path.join(CONFIG.projectRoot, 'tsconfig.json'))) {
      Logger.step('Running TypeScript type check...');
      this.exec('npx tsc --noEmit', { ignoreError: true });
    }

    const duration = this.timer.end('lint');
    this.results.lint = { status: 'success', duration };
    Logger.success(`Lint completed in ${this.timer.formatMs(duration)}`);
  }

  // ==================== STAGE: Test ====================
  async stageTest() {
    if (CONFIG.skipTests) {
      Logger.stage('STAGE 4: Test (SKIPPED)');
      this.results.test = { status: 'skipped', duration: 0 };
      return;
    }

    Logger.stage('STAGE 4: Run Tests');
    this.timer.start('test');

    const pkg = JSON.parse(fs.readFileSync(path.join(CONFIG.projectRoot, 'package.json'), 'utf8'));
    const scripts = pkg.scripts || {};

    if (scripts.test && scripts.test !== 'echo "Error: no test specified" && exit 1') {
      Logger.step('Running test suite...');

      const testEnv = {
        ...process.env,
        NODE_ENV: 'test',
        CI: 'true',
        FORCE_COLOR: '1',
      };

      // Run tests with coverage
      let testCommand = `${this.getRunCommand()} test`;

      // Add CI-specific flags for common test runners
      if (scripts.test.includes('jest')) {
        testCommand += ' -- --ci --coverage --forceExit';
        if (CONFIG.parallelTests) {
          testCommand += ` --maxWorkers=${Math.max(1, os.cpus().length - 1)}`;
        }
      } else if (scripts.test.includes('mocha')) {
        testCommand += ` -- --timeout ${CONFIG.testTimeout} --exit`;
      } else if (scripts.test.includes('vitest')) {
        testCommand += ' -- --run --coverage';
      }

      try {
        this.exec(testCommand, { env: testEnv, timeout: CONFIG.testTimeout });
      } catch (error) {
        this.results.test = { status: 'failed', duration: this.timer.end('test') };
        throw new Error('Tests failed');
      }

      // Copy coverage reports to artifacts
      const coverageDir = path.join(CONFIG.projectRoot, 'coverage');
      if (fs.existsSync(coverageDir)) {
        const artifactCoverage = path.join(CONFIG.artifactDir, 'coverage');
        fs.mkdirSync(artifactCoverage, { recursive: true });
        this.exec(`cp -r coverage/* "${artifactCoverage}/"`, { ignoreError: true, silent: true });
        Logger.step('Coverage report saved to artifacts');
      }
    } else {
      Logger.warn('No test script found or default test script detected');
    }

    // Run integration tests if available
    if (scripts['test:integration']) {
      Logger.step('Running integration tests...');
      this.exec(`${this.getRunCommand()} test:integration`, {
        env: { ...process.env, NODE_ENV: 'test', CI: 'true' },
        timeout: CONFIG.testTimeout * 2,
      });
    }

    // Run e2e tests if available
    if (scripts['test:e2e']) {
      Logger.step('Running e2e tests...');
      this.exec(`${this.getRunCommand()} test:e2e`, {
        env: { ...process.env, NODE_ENV: 'test', CI: 'true' },
        timeout: CONFIG.testTimeout * 3,
        ignoreError: true,
      });
    }

    const duration = this.timer.end('test');
    this.results.test = { status: 'success', duration };
    Logger.success(`Tests completed in ${this.timer.formatMs(duration)}`);
  }

  // ==================== STAGE: Security Audit ====================
  async stageSecurityAudit() {
    Logger.stage('STAGE 5: Security Audit');
    this.timer.start('security');

    Logger.step('Running dependency audit...');
    try {
      const auditCommands = {
        npm: 'npm audit --production --audit-level=high',
        yarn: 'yarn audit --level high',
        pnpm: 'pnpm audit --production --audit-level high',
      };
      this.exec(auditCommands[this.packageManager], { ignoreError: true });
    } catch {
      Logger.warn('Security audit found vulnerabilities (non-blocking)');
    }

    // Check for known vulnerable packages
    Logger.step('Checking for critical vulnerabilities...');
    try {
      this.exec('npx audit-ci --high', { ignoreError: true, silent: true });
    } catch {
      // audit-ci might not be installed
    }

    const duration = this.timer.end('security');
    this.results.security = { status: 'success', duration };
    Logger.success(`Security audit completed in ${this.timer.formatMs(duration)}`);
  }

  // ==================== STAGE: Build ====================
  async stageBuild() {
    Logger.stage('STAGE 6: Build Application');
    this.timer.start('build');

    const pkg = JSON.parse(fs.readFileSync(path.join(CONFIG.projectRoot, 'package.json'), 'utf8'));
    const scripts = pkg.scripts || {};

    // Set production build environment
    const buildEnv = {
      ...process.env,
      NODE_ENV: 'production',
      GENERATE_SOURCEMAP: 'true',
      BUILD_HASH: this.commitHash,
      BUILD_VERSION: this.version,
      BUILD_TIME: new Date().toISOString(),
    };

    // Clean previous build
    Logger.step('Cleaning previous build...');
    const buildDir = path.join(CONFIG.projectRoot, CONFIG.buildDir);
    if (fs.existsSync(buildDir)) {
      this.exec(`rm -rf "${buildDir}"`, { silent: true });
    }

    if (scripts.build) {
      Logger.step('Building application...');
      this.exec(`${this.getRunCommand()} build`, { env: buildEnv });
    } else {
      Logger.warn('No build script found. Skipping build step.');
    }

    // Verify build output
    if (scripts.build && !fs.existsSync(buildDir)) {
      // Check alternative build directories
      const altDirs = ['build', 'out', '.next', '.output', 'public'];
      const found = altDirs.find(d => fs.existsSync(path.join(CONFIG.projectRoot, d)));
      if (found) {
        Logger.step(`Build output found in: ${found}`);
      } else {
        Logger.warn(`Build directory '${CONFIG.buildDir}' not found. Build may use a different output path.`);
      }
    }

    // Generate build info file
    const buildInfo = {
      version: this.version,
      commit: this.commitHash,
      branch: this.branch,
      buildTime: new Date().toISOString(),
      nodeVersion: process.version,
      deployTarget: CONFIG.deployTarget,
    };

    if (fs.existsSync(buildDir)) {
      fs.writeFileSync(
        path.join(buildDir, 'build-info.json'),
        JSON.stringify(buildInfo, null, 2)
      );
    }

    // Save build info to artifacts
    fs.writeFileSync(
      path.join(CONFIG.artifactDir, 'build-info.json'),
      JSON.stringify(buildInfo, null, 2)
    );

    // Docker build if enabled
    if (CONFIG.dockerEnabled) {
      await this.dockerBuild();
    }

    const duration = this.timer.end('build');
    this.results.build = { status: 'success', duration };
    Logger.success(`Build completed in ${this.timer.formatMs(duration)}`);
  }

  async dockerBuild() {
    Logger.step('Building Docker image...');

    const tag = `${CONFIG.dockerImage}:${this.commitHash}`;
    const latestTag = `${CONFIG.dockerImage}:latest`;

    // Check for Dockerfile
    if (!fs.existsSync(path.join(CONFIG.projectRoot, 'Dockerfile'))) {
      Logger.step('No Dockerfile found, generating one...');
      this.generateDockerfile();
    }

    // Build with cache
    this.exec(
      `docker build \
        --tag ${tag} \
        --tag ${latestTag} \
        --build-arg BUILD_HASH=${this.commitHash} \
        --build-arg BUILD_VERSION=${this.version} \
        --cache-from ${latestTag} \
        .`,
      { ignoreError: false }
    );

    // Push to registry if configured
    if (CONFIG.dockerRegistry) {
      const registryTag = `${CONFIG.dockerRegistry}/${tag}`;
      this.exec(`docker tag ${tag} ${registryTag}`);
      this.execWithRetry(`docker push ${registryTag}`);
      Logger.step(`Pushed image: ${registryTag}`);
    }
  }

  generateDockerfile() {
    const dockerfile = `
FROM node:${process.version.replace('v', '')}-alpine AS builder
WORKDIR /app
COPY package*.json ./
RUN npm ci --production=false
COPY . .
RUN npm run build

FROM node:${process.version.replace('v', '')}-alpine AS runner
WORKDIR /app
ENV NODE_ENV=production
COPY package*.json ./
RUN npm ci --production --no-audit --no-fund
COPY --from=builder /app/${CONFIG.buildDir} ./${CONFIG.buildDir}
EXPOSE 3000
CMD ["node", "${CONFIG.buildDir}/index.js"]
`.trim();

    fs.writeFileSync(path.join(CONFIG.projectRoot, 'Dockerfile'), dockerfile);
    Logger.step('Generated Dockerfile');
  }

  // ==================== STAGE: Create Artifact ====================
  async stageCreateArtifact() {
    Logger.stage('STAGE 7: Create Deployment Artifact');
    this.timer.start('artifact');

    const artifactName = `deploy-${this.version}-${this.commitHash}-${Date.now()}.tar.gz`;
    const artifactPath = path.join(CONFIG.artifactDir, artifactName);

    // Determine what to include in the artifact
    const includeItems = [];
    const buildDir = CONFIG.buildDir;

    if (fs.existsSync(path.join(CONFIG.projectRoot, buildDir))) {
      includeItems.push(buildDir);
    }

    includeItems.push('package.json');

    const lockFiles = {
      npm: 'package-lock.json',
      yarn: 'yarn.lock',
      pnpm: 'pnpm-lock.yaml',
    };
    const lockFile = lockFiles[this.packageManager];
    if (fs.existsSync(path.join(CONFIG.projectRoot, lockFile))) {
      includeItems.push(lockFile);
    }

    // Include additional config files
    const configFiles = [
      '.env.production',
      'ecosystem.config.js',
      'pm2.config.js',
      'Procfile',
      'docker-compose.yml',
      'docker-compose.production.yml',
    ];

    for (const f of configFiles) {
      if (fs.existsSync(path.join(CONFIG.projectRoot, f))) {
        includeItems.push(f);
      }
    }

    // Include server directory if it exists
    if (fs.existsSync(path.join(CONFIG.projectRoot, 'server'))) {
      includeItems.push('server');
    }

    // Create tarball
    Logger.step(`Creating artifact: ${artifactName}`);
    const itemList = includeItems.join(' ');
    this.exec(`tar -czf "${artifactPath}" ${itemList}`, { silent: true });

    // Get artifact size
    const stats = fs.statSync(artifactPath);
    const sizeMB = (stats.size / (1024 * 1024)).toFixed(2);
    Logger.step(`Artifact size: ${sizeMB} MB`);

    // Generate checksum
    const crypto = require('crypto');
    const fileBuffer = fs.readFileSync(artifactPath);
    const checksum = crypto.createHash('sha256').update(fileBuffer).digest('hex');
    fs.writeFileSync(`${artifactPath}.sha256`, `${checksum}  ${artifactName}\n`);
    Logger.step(`Checksum: ${checksum.substring(0, 16)}...`);

    this.artifactPath = artifactPath;
    this.artifactName = artifactName;

    const duration = this.timer.end('artifact');
    this.results.artifact = { status: 'success', duration, size: sizeMB };
    Logger.success(`Artifact created in ${this.timer.formatMs(duration)}`);
  }

  // ==================== STAGE: Deploy ====================
  async stageDeploy() {
    if (CONFIG.skipDeploy) {
      Logger.stage('STAGE 8: Deploy (SKIPPED)');
      this.results.deploy = { status: 'skipped', duration: 0 };
      return;
    }

    Logger.stage('STAGE 8: Deploy to Production');
    this.timer.start('deploy');

    // Pre-deploy checks
    await this.preDeployChecks();

    // Save current deployment hash for potential rollback
    try {
      this.previousDeployHash = this.exec(
        `ssh -p ${CONFIG.deployPort} ${CONFIG.deployUser}@${CONFIG.deployHost} "cat ${CONFIG.deployPath}/build-info.json 2>/dev/null | node -e 'let d=\"\";process.stdin.on(\"data\",c=>d+=c);process.stdin.on(\"end\",()=>{try{console.log(JSON.parse(d).commit)}catch{console.log(\"\")}})'"`,
        { silent: true, ignoreError: true }
      );
    } catch {
      this.previousDeployHash = '';
    }

    if (CONFIG.dockerEnabled) {
      await this.deployDocker();
    } else {
      await this.deployTraditional();
    }

    const duration = this.timer.end('deploy');
    this.results.deploy = { status: 'success', duration };
    Logger.success(`Deployment completed in ${this.timer.formatMs(duration)}`);
  }

  async preDeployChecks() {
    Logger.step('Running pre-deploy checks...');

    // Verify SSH connectivity
    try {
      this.exec(
        `ssh -o ConnectTimeout=10 -o StrictHostKeyChecking=no -p ${CONFIG.deployPort} ${CONFIG.deployUser}@${CONFIG.deployHost} "echo ok"`,
        { silent: true }
      );
      Logger.step('SSH connectivity: OK');
    } catch {
      throw new Error(`Cannot connect to deploy host: ${CONFIG.deployHost}`);
    }

    // Verify disk space on remote
    try {
      const diskSpace = this.exec(
        `ssh -p ${CONFIG.deployPort} ${CONFIG.deployUser}@${CONFIG.deployHost} "df -h ${CONFIG.deployPath} | tail -1 | awk '{print \\$5}'"`,
        { silent: true }
      );
      const usedPercent = parseInt(diskSpace);
      if (usedPercent > 90) {
        Logger.warn(`Disk usage on deploy target is ${usedPercent}%`);
      }
      Logger.step(`Remote disk usage: ${diskSpace}`);
    } catch {
      Logger.warn('Could not check remote disk space');
    }
  }

  async deployTraditional() {
    const sshCmd = `ssh -o StrictHostKeyChecking=no -p ${CONFIG.deployPort} ${CONFIG.deployUser}@${CONFIG.deployHost}`;
    const scpCmd = `scp -o StrictHostKeyChecking=no -P ${CONFIG.deployPort}`;
    const remotePath = CONFIG.deployPath;
    const releaseDir = `${remotePath}/releases/${this.commitHash}-${Date.now()}`;
    const currentLink = `${remotePath}/current`;

    Logger.step('Creating release directory...');
    this.exec(`${sshCmd} "mkdir -p ${releaseDir}"`);

    // Upload artifact
    Logger.step('Uploading artifact...');
    this.execWithRetry(
      `${scpCmd} "${this.artifactPath}" ${CONFIG.deployUser}@${CONFIG.deployHost}:${releaseDir}/`
    );

    // Extract and setup
    Logger.step('Extracting and setting up...');
    this.exec(`${sshCmd} "cd ${releaseDir} && tar -xzf ${this.artifactName} && rm ${this.artifactName}"`);

    // Install production dependencies on remote
    Logger.step('Installing production dependencies on remote...');
    const remoteInstallCmds = {
      npm: 'npm ci --production --no-audit --no-fund',
      yarn: 'yarn install --frozen-lockfile --production --non-interactive',
      pnpm: 'pnpm install --frozen-lockfile --prod',
    };
    this.exec(`${sshCmd} "cd ${releaseDir} && ${remoteInstallCmds[this.packageManager]}"`);

    // Copy shared configs (like .env)
    Logger.step('Linking shared configurations...');
    this.exec(
      `${sshCmd} "[ -f ${remotePath}/shared/.env ] && cp ${remotePath}/shared/.env ${releaseDir}/.env || true"`,
      { ignoreError: true }
    );

    // Symlink current release
    Logger.step('Switching to new release...');
    this.exec(`${sshCmd} "ln -sfn ${releaseDir} ${currentLink}"`);

    // Run migrations if available
    Logger.step('Running post-deploy tasks...');
    this.exec(
      `${sshCmd} "cd ${currentLink} && [ -f package.json ] && node -e 'const p=require(\"./package.json\");if(p.scripts&&p.scripts[\"db:migrate\"]){process.exit(0)}else{process.exit(1)}' && npm run db:migrate || true"`,
      { ignoreError: true }
    );

    // Restart application
    Logger.step('Restarting application...');
    this.restartApplication(sshCmd, currentLink);

    // Cleanup old releases (keep last 5)
    Logger.step('Cleaning up old releases...');
    this.exec(
      `${sshCmd} "cd ${remotePath}/releases && ls -dt */ | tail -n +6 | xargs rm -rf"`,
      { ignoreError: true }
    );
  }

  restartApplication(sshCmd, currentLink) {
    // Try PM2 first
    try {
      this.exec(`${sshCmd} "command -v pm2 >/dev/null 2>&1"`, { silent: true });
      Logger.step('Restarting with PM2...');

      if (fs.existsSync(path.join(CONFIG.projectRoot, 'ecosystem.config.js'))) {
        this.exec(`${sshCmd} "cd ${currentLink} && pm2 reload ecosystem.config.js --env production"`);
      } else {
        this.exec(`${sshCmd} "cd ${currentLink} && pm2 reload all"`);
      }
      return;
    } catch {
      // PM2 not available
    }

    // Try systemd
    try {
      this.exec(`${sshCmd} "sudo systemctl restart app"`, { ignoreError: true });
      Logger.step('Restarted with systemd');
      return;
    } catch {
      // systemd not available or no permission
    }

    // Fallback: manual restart
    Logger.step('Using manual restart...');
    this.exec(
      `${sshCmd} "cd ${currentLink} && (kill \$(cat .pid 2>/dev/null) 2>/dev/null; sleep 2; NODE_ENV=production nohup node ${CONFIG.buildDir}/index.js > /dev/null 2>&1 & echo \$! > .pid)"`,
      { ignoreError: true }
    );
  }

  async deployDocker() {
    Logger.step('Deploying with Docker...');

    const sshCmd = `ssh -o StrictHostKeyChecking=no -p ${CONFIG.deployPort} ${CONFIG.deployUser}@${CONFIG.deployHost}`;
    const tag = `${CONFIG.dockerImage}:${this.commitHash}`;
    const imageName = CONFIG.dockerRegistry ? `${CONFIG.dockerRegistry}/${tag}` : tag;

    // Pull image on remote
    if (CONFIG.dockerRegistry) {
      Logger.step('Pulling image on remote...');
      this.exec(`${sshCmd} "docker pull ${imageName}"`);
    }

    // Stop and remove existing container
    Logger.step('Stopping existing container...');
    this.exec(`${sshCmd} "docker stop ${CONFIG.dockerImage} 2>/dev/null || true"`, { ignoreError: true });
    this.exec(`${sshCmd} "docker rm ${CONFIG.dockerImage} 2>/dev/null || true"`, { ignoreError: true });

    // Start new container
    Logger.step('Starting new container...');
    this.exec(
      `${sshCmd} "docker run -d \
        --name ${CONFIG.dockerImage} \
        --restart unless-stopped \
        -p 3000:3000 \
        --env-file ${CONFIG.deployPath}/shared/.env \
        ${imageName}"`
    );

    // Clean up old images
    this.exec(
      `${sshCmd} "docker image prune -f --filter 'label=app=${CONFIG.dockerImage}' 2>/dev/null"`,
      { ignoreError: true }
    );
  }

  // ==================== STAGE: Health Check ====================
  async stageHealthCheck() {
    if (CONFIG.skipDeploy || !CONFIG.healthCheckUrl) {
      Logger.stage('STAGE 9: Health Check (SKIPPED)');
      this.results.healthCheck = { status: 'skipped', duration: 0 };
      return;
    }

    Logger.stage('STAGE 9: Health Check');
    this.timer.start('healthCheck');

    const maxAttempts = Math.ceil(CONFIG.healthCheckTimeout / 5000);
    let healthy = false;

    for (let attempt = 1; attempt <= maxAttempts; attempt++) {
      Logger.step(`Health check attempt ${attempt}/${maxAttempts}...`);

      try {
        const http = CONFIG.healthCheckUrl.startsWith('https') ? require('https') : require('http');

        healthy = await new Promise((resolve) => {
          const req = http.get(CONFIG.healthCheckUrl, { timeout: 5000 }, (res) => {
            resolve(res.statusCode >= 200 && res.statusCode < 400);
          });
          req.on('error', () => resolve(false));
          req.on('timeout', () => { req.destroy(); resolve(false); });
        });

        if (healthy) {
          Logger.success('Health check passed!');
          break;
        }
      } catch {
        // Will retry
      }

      if (!healthy && attempt < maxAttempts) {
        await new Promise(resolve => setTimeout(resolve, 5000));
      }
    }

    if (!healthy) {
      const duration = this.timer.end('healthCheck');
      this.results.healthCheck = { status: 'failed', duration };

      if (CONFIG.rollbackOnFailure && this.previousDeployHash) {
        Logger.error('Health check failed! Initiating rollback...');
        await this.rollback();
      }

      throw new Error('Health check failed after all attempts');
    }

    const duration = this.timer.end('healthCheck');
    this.results.healthCheck = { status: 'success', duration };
    Logger.success(`Health check passed in ${this.timer.formatMs(duration)}`);
  }

  // ==================== Rollback ====================
  async rollback() {
    Logger.stage('ROLLBACK: Reverting to previous deployment');

    try {
      const sshCmd = `ssh -o StrictHostKeyChecking=no -p ${CONFIG.deployPort} ${CONFIG.deployUser}@${CONFIG.deployHost}`;
      const remotePath = CONFIG.deployPath;

      if (CONFIG.dockerEnabled) {
        // Docker rollback
        const previousTag = `${CONFIG.dockerImage}:${this.previousDeployHash}`;
        const imageName = CONFIG.dockerRegistry ? `${CONFIG.dockerRegistry}/${previousTag}` : previousTag;

        this.exec(`${sshCmd} "docker stop ${CONFIG.dockerImage} 2>/dev/null || true"`);
        this.exec(`${sshCmd} "docker rm ${CONFIG.dockerImage} 2>/dev/null || true"`);
        this.exec(`${sshCmd} "docker run -d --name ${CONFIG.dockerImage} --restart unless-stopped -p 3000:3000 --env-file ${remotePath}/shared/.env ${imageName}"`);
      } else {
        // Traditional rollback - find previous release
        const releases = this.exec(
          `${sshCmd} "ls -dt ${remotePath}/releases/*/ | head -2 | tail -1"`,
          { silent: true }
        );

        if (releases) {
          this.exec(`${sshCmd} "ln -sfn ${releases.trim()} ${remotePath}/current"`);
          this.restartApplication(sshCmd, `${remotePath}/current`);
        }
      }

      Logger.success('Rollback completed');
    } catch (error) {
      Logger.error(`Rollback failed: ${error.message}`);
    }
  }

  // ==================== STAGE: Notification ====================
  async stageNotify() {
    Logger.stage('STAGE 10: Notifications');
    this.timer.start('notify');

    const totalDuration = this.timer.totalElapsed();
    const allPassed = Object.values(this.results).every(r => r.status !== 'failed');

    // Generate summary
    const summary = this.generateSummary(totalDuration, allPassed);
    console.log(summary);

    // Save summary to artifacts
    fs.writeFileSync(
      path.join(CONFIG.artifactDir, 'pipeline-summary.txt'),
      summary.replace(/\x1b\[[0-9;]*m/g, '') // Strip ANSI colors for file
    );

    // Save JSON report
    const report = {
      pipeline: {
        status: allPassed ? 'success' : 'failed',
        duration: totalDuration,
        timestamp: new Date().toISOString(),
      },
      build: {
        version: this.version,
        commit: this.commitHash,
        branch: this.branch,
        message: this.commitMessage,
      },
      stages: this.results,
    };

    fs.writeFileSync(
      path.join(CONFIG.artifactDir, 'pipeline-report.json'),
      JSON.stringify(report, null, 2)
    );

    // Slack notification
    if (CONFIG.notifySlack) {
      await this.notifySlack(allPassed, totalDuration);
    }

    const duration = this.timer.end('notify');
    this.results.notify = { status: 'success', duration };
  }

  generateSummary(totalDuration, allPassed) {
    const line = '─'.repeat(60);
    let summary = `\n${COLORS.cyan}${line}${COLORS.reset}\n`;
    summary += `${allPassed ? COLORS.green : COLORS.red}`;
    summary += `  Pipeline ${allPassed ? 'SUCCEEDED' : 'FAILED'} `;
    summary += `(${this.timer.formatMs(totalDuration)})${COLORS.reset}\n`;
    summary += `${COLORS.cyan}${line}${COLORS.reset}\n`;
    summary += `  Version:  ${this.version}\n`;
    summary += `  Commit:   ${this.commitHash}\n`;
    summary += `  Branch:   ${this.branch}\n`;
    summary += `  Target:   ${CONFIG.deployTarget}\n`;
    summary += `${COLORS.cyan}${line}${COLORS.reset}\n`;

    for (const [stage, result] of Object.entries(this.results)) {
      const icon = result.status === 'success' ? '✅' :
                   result.status === 'failed' ? '❌' :
                   result.status === 'skipped' ? '⏭️' : '❓';
      const duration = result.duration ? this.timer.formatMs(result.duration) : '-';
      const extra = result.cacheHit !== undefined ? ` (cache: ${result.cacheHit ? 'hit' : 'miss'})` : '';
      summary += `  ${icon} ${stage.padEnd(15)} ${duration.padStart(10)}${extra}\n`;
    }

    summary += `${COLORS.cyan}${line}${COLORS.reset}\n`;
    return summary;
  }

  async notifySlack(success, duration) {
    Logger.step('Sending Slack notification...');

    const payload = {
      text: `${success ? '✅' : '❌'} Deployment ${success ? 'succeeded' : 'failed'}`,
      blocks: [
        {
          type: 'section',
          text: {
            type: 'mrkdwn',
            text: `*${success ? '✅ Deployment Succeeded' : '❌ Deployment Failed'}*\n` +
                  `Version: \`${this.version}\` | Commit: \`${this.commitHash}\`\n` +
                  `Branch: \`${this.branch}\` | Duration: ${this.timer.formatMs(duration)}\n` +
                  `Target: ${CONFIG.deployTarget}`,
          },
        },
      ],
    };

    try {
      const https = require('https');
      const url = new URL(CONFIG.notifySlack);

      await new Promise((resolve, reject) => {
        const req = https.request({
          hostname: url.hostname,
          path: url.pathname,
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
        }, (res) => {
          res.on('data', () => {});
          res.on('end', resolve);
        });

        req.on('error', reject);
        req.write(JSON.stringify(payload));
        req.end();
      });

      Logger.step('Slack notification sent');
    } catch (error) {
      Logger.warn(`Failed to send Slack notification: ${error.message}`);
    }
  }

  // ==================== Helpers ====================
  getRunCommand() {
    const commands = {
      npm: 'npm run',
      yarn: 'yarn',
      pnpm: 'pnpm',
    };
    return commands[this.packageManager];
  }

  // ==================== Main Pipeline Execution ====================
  async run() {
    Logger.banner('CI/CD PIPELINE - Rapid Deployment System');

    const stages = [
      () => this.stageInit(),
      () => this.stageInstall(),
      () => this.stageLint(),
      () => this.stageTest(),
      () => this.stageSecurityAudit(),
      () => this.stageBuild(),
      () => this.stageCreateArtifact(),
      () => this.stageDeploy(),
      () => this.stageHealthCheck(),
      () => this.stageNotify(),
    ];

    let exitCode = 0;

    for (const stage of stages) {
      try {
        await stage();
      } catch (error) {
        Logger.error(`Pipeline failed: ${error.message}`);

        if (process.env.DEBUG) {
          console.error(error.stack);
        }

        exitCode = 1;

        // Still run notification on failure
        try {
          await this.stageNotify();
        } catch {
          // Ignore notification errors
        }

        break;
      }
    }

    const totalDuration = this.timer.totalElapsed();
    Logger.banner(
      exitCode === 0
        ? `PIPELINE SUCCEEDED (${this.timer.formatMs(totalDuration)})`
        : `PIPELINE FAILED (${this.timer.formatMs(totalDuration)})`
    );

    process.exit(exitCode);
  }
}

// ==================== CLI Interface ====================
function printHelp() {
  console.log(`
CI/CD Pipeline Script

Usage: node pipeline.js [options]

Options:
  --help                    Show this help
  --skip-tests              Skip test stage
  --skip-lint               Skip lint stage
  --skip-deploy             Skip deploy stage (build only)
  --docker                  Enable Docker build and deploy
  --target <env>            Set deploy target (default: production)
  --host <host>             Set deploy host
  --path <path>             Set deploy path
  --health-check <url>      Set health check URL
  --no-rollback             Disable rollback on failure

Environment Variables:
  PROJECT_ROOT              Project root directory
  NODE_ENV                  Node environment
  DEPLOY_TARGET             Deploy target environment
  DEPLOY_HOST               Remote host for deployment
  DEPLOY_USER               SSH user for deployment
  DEPLOY_PATH               Remote path for deployment
  DEPLOY_PORT               SSH port (default: 22)
  BUILD_DIR                 Build output directory (default: dist)
  SKIP_TESTS                Skip tests (true/false)
  SKIP_LINT                 Skip linting (true/false)
  SKIP_DEPLOY               Skip deployment (true/false)
  DOCKER_ENABLED            Enable Docker (true/false)
  DOCKER_IMAGE              Docker image name
  DOCKER_REGISTRY           Docker registry URL
  SLACK_WEBHOOK_URL         Slack webhook for notifications
  HEALTH_CHECK_URL          URL for post-deploy health check
  HEALTH_CHECK_TIMEOUT      Health check timeout in ms
  ROLLBACK_ON_FAILURE       Auto-rollback on failure (true/false)
  `);
}

// Parse CLI arguments
const args = process.argv.slice(2);
if (args.includes('--help') || args.includes('-h')) {
  printHelp();
  process.exit(0);
}

for (let i = 0; i < args.length; i++) {
  switch (args[i]) {
    case '--skip-tests':
      CONFIG.skipTests = true;
      break;
    case '--skip-lint':
      CONFIG.skipLint = true;
      break;
    case '--skip-deploy':
      CONFIG.skipDeploy = true;
      break;
    case '--docker':
      CONFIG.dockerEnabled = true;
      break;
    case '--target':
      CONFIG.deployTarget = args[++i];
      break;
    case '--host':
      CONFIG.deployHost = args[++i];
      break;
    case '--path':
      CONFIG.deployPath = args[++i];
      break;
    case '--health-check':
      CONFIG.healthCheckUrl = args[++i];
      break;
    case '--no-rollback':
      CONFIG.rollbackOnFailure = false;
      break;
  }
}

// Run the pipeline
const pipeline = new Pipeline();
pipeline.run().catch((error) => {
  Logger.error(`Unhandled error: ${error.message}`);
  process.exit(1);
});